  ('funbrain', 'verbal', '{"text": "What is a synonym for HUGE?", "pack": "cbse_verbal_puc100_foundational"}'::jsonb, '["Narrow", "Tiny", "Brief", "Enormous"]'::jsonb, 3, 'Huge means very large; enormous is a close synonym (also: giant).'),
