-- CBSE PUC foundational verbal (100), funbrain / verbal. Pack: cbse_verbal_puc100_foundational.
-- Idempotent: delete this pack in verbal, then insert.

BEGIN;

DELETE FROM public.play_questions
WHERE domain = 'funbrain'
  AND category = 'verbal'
  AND (content->>'pack') = 'cbse_verbal_puc100_foundational';


COMMIT;
